(function(){
  // Expose a promise so app code can wait until SignalR is actually available.
  if (window.__signalRReady) return;

  function done(ok){
    try {
      window.__signalRReadyResolve && window.__signalRReadyResolve(ok);
    } catch (e) {}
  }

  window.__signalRReady = new Promise(function(resolve){
    window.__signalRReadyResolve = resolve;
  });

  if (window.signalR && window.signalR.HubConnectionBuilder) {
    done(true);
    return;
  }

  var s = document.createElement('script');
  s.src = 'https://cdn.jsdelivr.net/npm/%40microsoft/signalr@8.0.11/dist/browser/signalr.min.js';
  s.crossOrigin = 'anonymous';
  s.onload = function(){
    done(!!(window.signalR && window.signalR.HubConnectionBuilder));
  };
  s.onerror = function(){
    console.warn('Failed to load SignalR client bundle');
    done(false);
  };
  document.head.appendChild(s);
})();
